import { useState } from "react";
import { createPortal } from "react-dom";
import { createPost } from "../firebase/posts";
import { generateBlog } from "../ai/aiService";
import toast from "react-hot-toast";

export default function WriteModal({ onClose, onPublished, isDemo, onDemoPublish }) {
  const [form, setForm] = useState({
    title: "",
    content: "",
  });

  const [imagePreview, setImagePreview] = useState(null);
  const [aiDraft, setAiDraft] = useState("");

  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  // 🖼️ IMAGE HANDLER
  const handleImage = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (ev) => setImagePreview(ev.target.result);
    reader.readAsDataURL(file);
  };

  // 🤖 AI GENERATE
  const handleGenerate = async () => {
    if (!form.title.trim()) {
      toast.error("Enter title first");
      return;
    }

    toast.loading("Generating...");
    try {
      const content = await generateBlog(form.title);
      setAiDraft(content);
      toast.dismiss();
      toast.success("AI ready!");
    } catch {
      toast.dismiss();
      toast.error("AI failed");
    }
  };

  // USE AI CONTENT
  const handleUse = () => {
    setForm((f) => ({ ...f, content: aiDraft }));
    setAiDraft("");
  };

  // 🚀 PUBLISH
  const handlePublish = async () => {
    if (!form.title || !form.content) {
      toast.error("Fill all fields");
      return;
    }

    const postData = {
      ...form,
      image: imagePreview,
    };

    if (isDemo) {
      onDemoPublish?.(postData);
    } else {
      await createPost(postData);
    }

    toast.success("Published!");
    onPublished?.();
    onClose();
  };

  return createPortal(
    <div style={s.backdrop}>
      <div style={s.modal}>
        <button style={s.close} onClick={onClose}>✕</button>

        <h2 style={s.title}>✍️ Write Post</h2>

        {/* TITLE */}
        <input
          style={s.input}
          placeholder="Enter title..."
          value={form.title}
          onChange={(e) => set("title", e.target.value)}
        />

        {/* IMAGE */}
        <div style={s.imageBox}>
          {imagePreview ? (
            <img src={imagePreview} style={s.img} />
          ) : (
            <label style={s.upload}>
              📷 Upload Cover Image
              <input type="file" hidden onChange={handleImage} />
            </label>
          )}
        </div>

        {/* CONTENT */}
        <textarea
          style={s.textarea}
          placeholder="Write your content..."
          value={form.content}
          onChange={(e) => set("content", e.target.value)}
        />

        {/* AI BUTTON */}
        <button style={s.aiBtn} onClick={handleGenerate}>
          ✨ Generate Blog with AI
        </button>

        {/* AI PREVIEW */}
        {aiDraft && (
          <div style={s.preview}>
            <div style={s.previewText}>{aiDraft}</div>

            <button style={s.useBtn} onClick={handleUse}>
              ✅ Use this content
            </button>
          </div>
        )}

        {/* PUBLISH */}
        <button style={s.publish} onClick={handlePublish}>
          🚀 Publish
        </button>
      </div>
    </div>,
    document.body
  );
}

const s = {
  backdrop: {
    position: "fixed",
    inset: 0,
    background: "rgba(0,0,0,0.6)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    zIndex: 999999,
  },

  modal: {
    background: "#fff",
    padding: 20,
    borderRadius: 16,
    width: 520,
    position: "relative",
  },

  close: {
    position: "absolute",
    top: 10,
    right: 10,
    border: "none",
    background: "#eee",
    borderRadius: "50%",
    width: 30,
    height: 30,
  },

  title: {
    fontSize: "1.4rem",
    fontWeight: 700,
    marginBottom: 12,
  },

  input: {
    width: "100%",
    padding: 10,
    borderRadius: 10,
    border: "1px solid #ddd",
    marginBottom: 10,
  },

  textarea: {
    width: "100%",
    height: 120,
    padding: 10,
    borderRadius: 10,
    border: "1px solid #ddd",
    marginBottom: 10,
  },

  imageBox: {
    marginBottom: 10,
  },

  upload: {
    display: "block",
    padding: 15,
    border: "2px dashed #ccc",
    borderRadius: 10,
    textAlign: "center",
    cursor: "pointer",
  },

  img: {
    width: "100%",
    height: 150,
    objectFit: "cover",
    borderRadius: 10,
  },

  aiBtn: {
    width: "100%",
    padding: 12,
    borderRadius: 10,
    background: "#2563eb",
    color: "#fff",
    border: "none",
    marginBottom: 10,
  },

  preview: {
    border: "1px solid #ddd",
    padding: 10,
    borderRadius: 10,
    marginBottom: 10,
  },

  previewText: {
    maxHeight: 120,
    overflow: "auto",
    marginBottom: 8,
  },

  useBtn: {
    width: "100%",
    padding: 8,
    background: "green",
    color: "#fff",
    border: "none",
    borderRadius: 8,
  },

  publish: {
    width: "100%",
    padding: 12,
    background: "#1d4ed8",
    color: "#fff",
    border: "none",
    borderRadius: 10,
  },
};
